mapper.select:
SELECT count(*) FROM hm_query.dim_warehouse

    AND warehouse_code = #{warehouseCode}
    AND warehouse_name LIKE CONCAT('%', #{warehouseName}, '%')
    AND warehouse_type = #{warehouseType}
    AND city = #{city}
    AND state = #{state}
    AND pincode = #{pincode}
    AND is_active = CAST(#{isActive} AS boolean)
    AND (
        warehouse_name LIKE CONCAT('%', #{q}, '%')
        OR warehouse_code LIKE CONCAT('%', #{q}, '%')
        OR city LIKE CONCAT('%', #{q}, '%')
        OR state LIKE CONCAT('%', #{q}, '%')
    )

SELECT dw.id, dw.warehouse_code as "warehouseCode", dw.warehouse_name as "warehouseName", dw.warehouse_type as "warehouseType", dw.city, dw.state, dw.pincode, dw.country, dw.contact_phone as "contactPhone", dw.contact_email as "contactEmail", dw.manager_id as "managerId", dw.max_capacity_units as "maxCapacityUnits", dw.current_utilization_pct as "currentUtilizationPct", dw.is_active as "isActive", dw.is_returns_center as "isReturnsCenter", dw.total_skus as "totalSkus", dw.total_units as "totalUnits", dw.created_time as "createdTime" FROM hm_query.dim_warehouse dw
AND dw.warehouse_code = #{warehouseCode} AND dw.warehouse_name LIKE CONCAT('%', #{warehouseName}, '%') AND dw.warehouse_type = #{warehouseType} AND dw.city = #{city} AND dw.state = #{state} AND dw.pincode = #{pincode} AND dw.is_active = CAST(#{isActive} AS boolean) AND ( dw.warehouse_name LIKE CONCAT('%', #{q}, '%') OR dw.warehouse_code LIKE CONCAT('%', #{q}, '%') OR dw.city LIKE CONCAT('%', #{q}, '%') OR dw.state LIKE CONCAT('%', #{q}, '%') )
${orderby} ${pagination}

SELECT count(*) FROM hm_query.warehouse_locations_flat

    AND warehouse_id = #{warehouseId}
    AND location_type = #{locationType}
    AND zone = #{zone}
    AND is_active = CAST(#{isActive} AS boolean)
    AND (
        location_code LIKE CONCAT('%', #{q}, '%')
        OR warehouse_name LIKE CONCAT('%', #{q}, '%')
        OR zone LIKE CONCAT('%', #{q}, '%')
    )

SELECT id, warehouse_id as "warehouseId", warehouse_name as "warehouseName", location_code as "locationCode", zone, aisle, shelf, bin, location_type as "locationType", capacity_units as "capacityUnits", current_units as "currentUnits", is_active as "isActive" FROM hm_query.warehouse_locations_flat
AND warehouse_id = #{warehouseId} AND location_type = #{locationType} AND zone = #{zone} AND is_active = CAST(#{isActive} AS boolean) AND ( location_code LIKE CONCAT('%', #{q}, '%') OR warehouse_name LIKE CONCAT('%', #{q}, '%') OR zone LIKE CONCAT('%', #{q}, '%') )
${orderby} ${pagination}

SELECT count(*) FROM hm_query.warehouse_inventory_flat

    AND warehouse_id = #{warehouseId}
    AND location_id = #{locationId}
    AND zone = #{zone}
    AND location_type = #{locationType}
    AND (
        sku LIKE CONCAT('%', #{q}, '%')
        OR product_name LIKE CONCAT('%', #{q}, '%')
        OR brand LIKE CONCAT('%', #{q}, '%')
        OR location_code LIKE CONCAT('%', #{q}, '%')
    )

SELECT wi.warehouse_inventory_id as "warehouseInventoryId", wi.product_id as "productId", wi.variant_id as "variantId", wi.sku as "sku", wi.quantity_on_hand as "expectedQuantity", wi.quantity_reserved as "quantityReserved", wi.quantity_available as "quantityAvailable", wi.quantity_damaged as "quantityDamaged", wi.last_counted_at as "lastCountedAt", wi.location_id as "locationId", wi.location_code as "locationCode", wi.zone as "zone", wi.aisle as "aisle", wi.shelf as "shelf", wi.bin as "bin", wi.location_type as "locationType", wi.product_name as "productName", wi.brand as "brand" FROM hm_query.warehouse_inventory_flat wi
AND wi.warehouse_id = #{warehouseId} AND wi.location_id = #{locationId} AND wi.zone = #{zone} AND wi.location_type = #{locationType} AND ( wi.sku LIKE CONCAT('%', #{q}, '%') OR wi.product_name LIKE CONCAT('%', #{q}, '%') OR wi.brand LIKE CONCAT('%', #{q}, '%') OR wi.location_code LIKE CONCAT('%', #{q}, '%') )
${orderby} ${pagination}
